from typing import List

class Solution:
    def numIslands(self, grid: List[List[str]]) -> int:
        if not grid or not grid[0]:
            return 0

        m, n = len(grid), len(grid[0])
        count = 0

        def dfs(i: int, j: int) -> None:
            # 越界或遇到水，停止
            if i < 0 or i >= m or j < 0 or j >= n or grid[i][j] == '0':
                return
            # 沉岛：标记为已访问
            grid[i][j] = '0'
            # 四个方向探索
            dfs(i + 1, j)
            dfs(i - 1, j)
            dfs(i, j + 1)
            dfs(i, j - 1)

        for i in range(m):
            for j in range(n):
                if grid[i][j] == '1':
                    count += 1      # 发现新岛屿
                    dfs(i, j)       # 沉没整个岛屿

        return count


# BFS 版本
from collections import deque

class SolutionBFS:
    def numIslands(self, grid: List[List[str]]) -> int:
        if not grid or not grid[0]:
            return 0

        m, n = len(grid), len(grid[0])
        count = 0

        for i in range(m):
            for j in range(n):
                if grid[i][j] == '1':
                    count += 1
                    # BFS
                    queue = deque([(i, j)])
                    grid[i][j] = '0'
                    while queue:
                        x, y = queue.popleft()
                        for dx, dy in [(0, 1), (0, -1), (1, 0), (-1, 0)]:
                            nx, ny = x + dx, y + dy
                            if 0 <= nx < m and 0 <= ny < n and grid[nx][ny] == '1':
                                grid[nx][ny] = '0'
                                queue.append((nx, ny))

        return count
